script.text:

function loadFormDir(f) {
  if (f._action == 'Edit') setItemDisable(f, 'ma_so', true);
      else if (f._action == 'New') setItemDisable(f, 'ma_so', false);
  var v = f.getItem('kind').value;
	setItemDisableByKind(f, v);
}

function onChange$Item(o) {
  var f = o.parentForm, name = o.field.Name;
  switch (name) {
    case 'ma_so':
      if (f.getItem('ma_so_in').value == '') f.getItem('ma_so_in').value = o.value.toUpperCase();
      break;
    case 'kind':
      onChange$FunCalWay(f, true);
      break;
    default:
      break;
  }
}

function onChange$FunCalWay(f, force) {window.setTimeout(String.format('onFocus$FunCalWay(\'{0}\', {1});', f._id, force ? 1 : 0), 2);}
function onFocus$FunCalWay(id, force) {
  var f = $find(id), v = f.getItem('kind').value, t1 = f.getItem('cach_tinh2'), t2 = f._findButton('Ok');
  setItemDisableByKind(f, v);
	if (v != 9) {setItemLive(t1, t2, true);}
		else {setItemLive(t2, t1, true);}
}
function setItemDisableByKind(f, v) {
  switch (v) {
    case '1':
			f.getItem('cach_tinh').disabled = false;
			f.getItem('cach_tinh2').disabled = false;
			f.getItem('loai_sd').disabled = true;
      break;
    case '2':
			f.getItem('cach_tinh').disabled = false;
			f.getItem('cach_tinh2').disabled = false;
			f.getItem('loai_sd').disabled = false;
      break;
    case '9':
			f.getItem('cach_tinh').value = '';
			f.getItem('cach_tinh2').value = '';
			f.getItem('cach_tinh').disabled = true;
			f.getItem('cach_tinh2').disabled = true;
			f.getItem('loai_sd').disabled = true;
      break;			
    default:
      break;
  }
}

function setItemDisable(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if (o.a) $common.setVisible(o.a, !v);
    o.disabled = v;
  }
}

function setItemLive(t1, t2, type) {
  if (type) {if (t2.live) {t1.disabled = false; t1.focus();}}
    else {if (t1.live) {t2.disabled = false; t2.focus();}}
}

      &ScriptIrregular;
